<template><view class="page"><xy-header title="我的订单"/><view class="wrap"><view v-for="order in orders" :key="order.orderNo" class="card" @click="detail(order)"><view class="head"><text>{{order.orderNo}}</text><text>{{labels[order.status]||order.status}}</text></view><view class="goods"><image v-if="order.coverUrl" :src="order.coverUrl" mode="aspectFill"/><text>{{order.productName}} × {{order.quantity}}</text></view><view class="total">实付 ¥{{order.payableAmount}}</view></view><view v-if="!orders.length" class="empty">暂无订单</view></view></view></template>
<script>
import {appRequest,ensureMemberSession,showRequestError} from '../../utils/api'
export default{data(){return{orders:[],labels:{PENDING_PAYMENT:'待支付',PAID:'待发货',SHIPPED:'待收货',COMPLETED:'已完成'}}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.orders=await appRequest({url:'/app/orders'})}catch(e){showRequestError(e)}},detail(order){uni.navigateTo({url:`/pages/order/detail?orderNo=${order.orderNo}`})}}}
</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{margin-bottom:20rpx;padding:26rpx;border-radius:22rpx;background:#fff}.head{display:flex;justify-content:space-between;color:var(--xy-primary);font-size:23rpx}.goods{display:flex;gap:18rpx;align-items:center;margin-top:20rpx}.goods image{width:100rpx;height:100rpx;border-radius:14rpx;background:var(--xy-mint)}.total{text-align:right;margin-top:18rpx;font-weight:700}.empty{padding:140rpx;text-align:center;color:var(--xy-muted)}</style>
